# 批量读取多个样本的数据文件
# 假设你有文件: sample1.txt, sample2.txt, sample3.txt

# TODO: 编写代码批量读取并合并

# 1. 创建一个函数，读取单个样本文件
# 格式：两列，gene 和 expression
read_sample &lt;- function(filename, sample_name) {
  # 读取数据
  data &lt;- read.table(filename, header = TRUE, sep = "\t")
  # 重命名表达列为样本名
  names(data)[2] &lt;- sample_name
  return(data)
}

# 2. 使用循环批量读取多个样本并合并
# （模拟数据）
sample_files &lt;- c("sample1", "sample2", "sample3")
combined_data &lt;- NULL

for (file in sample_files) {
  # 模拟读取
  temp_data &lt;- data.frame(
    gene = c("TP53", "BRCA1", "EGFR"),
    expression = runif(3, 5, 20)
  )
  names(temp_data)[2] &lt;- file

  if (is.null(combined_data)) {
    combined_data &lt;- temp_data
  } else {
    combined_data &lt;- merge(combined_data, temp_data, by = "gene")
  }
}

